salary_ranges = {
    "应届生": ["150-300/天","120-250/天","6-10K","5-8K","4-7K","7-12K","100-200/天"],
    "1-3年": ["8-15K","10-18K","12-20K","12-22K","15-25K","15-28K","18-30K","10-16K","8-14K","12-18K","14-24K"],
    "3-5年": ["15-28K","18-35K","20-35K","25-40K","18-30K","15-25K","20-30K","22-38K"],
    "5年以上": ["25-45K","30-50K","35-60K","40-60K","30-55K","35-70K","45-80K"],
}

# Company pools per category
cat_company_pool = {
    "design": companies["tech"]+companies["brand"]+companies["agency"],
    "media": companies["media"]+companies["tech"][:8],
    "performing": companies["perform"]+companies["music"]+companies["brand"],
    "education": companies["edu"],
}

jobs = []
job_id = 1

# Generate: each template = ~55 variants (about 10000 total)
variants_per_template = max(1, 10000 // len(templates))

for (title, cat_num, desc, req, pref, majors, exps) in templates:
    cat_key, cat_name, dir_cat = cat_map[cat_num]
    pool = cat_company_pool.get(cat_key, companies["tech"]+companies["brand"]+companies["agency"])
    used = set()
    for _ in range(variants_per_template):
        if len(jobs) >= 10000: break
        company, company_city = random.choice(pool)
        attempts = 0
        while company in used and attempts < 40:
            company, company_city = random.choice(pool)
            attempts += 1
        used.add(company)
        city, city_code = random.choice(cities[:40])
        exp = random.choice(exps)
        salary = random.choice(salary_ranges.get(exp, ["面议"]))
        link = company_urls.get(company, f'https://www.zhipin.com/web/geek/job?query={title}&city={city_code}' if city_code else f'https://www.zhipin.com/web/geek/job?query={title}')
        n_req = random.randint(3, min(6, len(req)))
        req_skills = random.sample(req, n_req)
        n_pref = random.randint(2, min(4, len(pref)))
        pref_skills = random.sample(pref, n_pref)
        jobs.append({"id":job_id,"title":title,"category":cat_key,"catName":cat_name,"dirCategory":dir_cat,"dirKey":title,
                      "company":company,"city":city,"salary":salary,"link":link,
                      "desc":desc,"reqSkills":req_skills,"prefSkills":pref_skills,
                      "reqMajor":majors,"expLevel":exp})
        job_id += 1

jobs = jobs[:10000]
for i, j in enumerate(jobs): j["id"] = i+1

from collections import Counter
nc = Counter(j["title"] for j in jobs)
cc = Counter(j["category"] for j in jobs)
print(f"总岗位数: {len(jobs)}")
print(f"不同细分岗位: {len(nc)}")
print(f"类别分布: {dict(cc)}")

with open('jobs-data.json', 'w', encoding='utf-8') as f:
    json.dump(jobs, f, ensure_ascii=False, separators=(',', ':'))

